$products = 0; $slots = 0; $miss = 0; $mismatch = [];
foreach ($data as $r) {
    $q = DB::table('products')->where('external_id', $r['ext']);
    if ($r['code'] !== '') $q->where('product_code', $r['code']);
    $row = $q->select('id','name')->first();
    if ($row === null) { $miss++; continue; }
    $arr = json_decode($row->name, true);
    if (!is_array($arr)) continue;
    $chg = false;
    foreach ($r['bad'] as $loc => $badVal) {
        if (!array_key_exists($loc, $arr)) continue;
        if ($arr[$loc] === $badVal) { unset($arr[$loc]); $slots++; $chg = true; }
        elseif (is_string($arr[$loc]) && strpos($arr[$loc], '??') !== false) { $mismatch[] = $r['ext'].'|'.$r['code'].'|'.$loc; }
    }
    if ($chg) {
        DB::table('products')->where('id', $row->id)
            ->update(['name' => json_encode($arr, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES)]);
        $products++;
    }
}
echo "Wyczyszczono krzaki: {$products} produktow, {$slots} slotow (nie znaleziono: {$miss}, z ".count($data).")\n";
echo "Sloty z '??' ale INNA wartoscia niz nasz krzak (nie ruszone): ".count($mismatch)."\n";
foreach (array_slice($mismatch, 0, 20) as $m) echo "  $m\n";

// DIAGNOSTYKA koncowa: ile '??' zostalo w products.name na CALEJ bazie
$left = DB::table('products')->where('name', 'like', '%??%')->select('id','external_id','product_code','name')->get();
$perLoc = [];
foreach ($left as $p) {
    $arr = json_decode($p->name, true) ?: [];
    foreach ($arr as $loc => $v) if (is_string($v) && strpos($v, '??') !== false) $perLoc[$loc] = ($perLoc[$loc] ?? 0) + 1;
}
ksort($perLoc);
echo "\nPo sprzataniu — produkty z '??' w name: ".count($left)."\n";
foreach ($perLoc as $loc => $n) echo "  $loc : $n\n";
foreach ($left->take(15) as $p) {
    $arr = json_decode($p->name, true) ?: [];
    $badLocs = implode(',', array_keys(array_filter($arr, fn($v) => is_string($v) && strpos($v, '??') !== false)));
    echo "  #{$p->id} ext={$p->external_id} {$p->product_code} [{$badLocs}]\n";
}